package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_withMultipleValues() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormat_withNullValue() throws IOException {
        String result = csvFormat.format("a", null, "c");
        // The default nullString is null, so null is printed as empty
        assertEquals("a,,c", result);
    }

    @Test
    void testFormat_withEmptyValues() throws IOException {
        String result = csvFormat.format("", "", "");
        assertEquals(",,", result); // 3 empty values produce 2 commas, no trailing comma by default
    }

    @Test
    void testFormat_withEmptyArray() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormat_ioExceptionWrappedInIllegalStateException() throws Exception {
        // Create a spy of CSVFormat.DEFAULT by copying all fields via reflection to a new instance
        CSVFormat spyFormat = createSpyCSVFormat(csvFormat);

        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("mocked IO exception")).when(mockPrinter).printRecord((Object[]) any());
        doNothing().when(mockPrinter).close();

        // Override the printer() method by reflection to return our mockPrinter
        Field printerMethodField = CSVFormat.class.getDeclaredField("printer");
        // Since printer() is a method, we cannot override it by reflection easily,
        // instead, we use a spy with Mockito's doReturn for the method call.
        // But CSVFormat is final, so we can't spy it directly.
        // So we create a subclass to override printer() method.

        CSVFormat spyFormatWithPrinter = new CSVFormat(spyFormat.getDelimiter(),
                spyFormat.getQuoteCharacter(),
                spyFormat.getQuoteMode(),
                spyFormat.getCommentMarker(),
                spyFormat.getEscapeCharacter(),
                spyFormat.getIgnoreSurroundingSpaces(),
                spyFormat.getIgnoreEmptyLines(),
                spyFormat.getRecordSeparator(),
                spyFormat.getNullString(),
                null,
                spyFormat.getHeader(),
                spyFormat.getSkipHeaderRecord(),
                spyFormat.getAllowMissingColumnNames(),
                spyFormat.getIgnoreHeaderCase(),
                spyFormat.getTrim(),
                spyFormat.getTrailingDelimiter(),
                spyFormat.getAutoFlush()) {
            @Override
            public CSVPrinter printer() {
                return mockPrinter;
            }
        };

        IllegalStateException ex = assertThrows(IllegalStateException.class, () -> {
            try (CSVPrinter printer = spyFormatWithPrinter.printer()) {
                printer.printRecord((Object[]) new Object[] { "a" });
            } catch (IOException e) {
                throw new IllegalStateException(e);
            }
        });
        assertTrue(ex.getCause() instanceof IOException);
        assertEquals("mocked IO exception", ex.getCause().getMessage());
    }

    // Helper method to create a CSVFormat instance copying all fields from an existing one
    private static CSVFormat createSpyCSVFormat(CSVFormat original) throws Exception {
        return new CSVFormat(original.getDelimiter(),
                original.getQuoteCharacter(),
                original.getQuoteMode(),
                original.getCommentMarker(),
                original.getEscapeCharacter(),
                original.getIgnoreSurroundingSpaces(),
                original.getIgnoreEmptyLines(),
                original.getRecordSeparator(),
                original.getNullString(),
                null,
                original.getHeader(),
                original.getSkipHeaderRecord(),
                original.getAllowMissingColumnNames(),
                original.getIgnoreHeaderCase(),
                original.getTrim(),
                original.getTrailingDelimiter(),
                original.getAutoFlush());
    }
}
